INSERT INTO case_questions (id, title, type, difficulty, description, context, key_issues) VALUES
('retail-profit', 'Retail chain profit decline', 'profitability', 'medium', 'A retail chain client''s profits have fallen 20% over the past two years while revenue is roughly flat. Diagnose the problem and recommend improvements.', 'The client operates 500 stores nationwide, mainly FMCG and household goods. Competitors include large supermarkets and e-commerce platforms.', '["Revenue mix analysis","Cost structure (fixed vs. variable)","Same-store sales vs. new stores","Category mix shifts","Competitive landscape"]'::jsonb),
('coffee-china', 'Coffee brand China market entry', 'market_entry', 'medium', 'A U.S. specialty coffee brand wants to enter China. Assess the market opportunity and outline an entry strategy.', 'The brand has 200 U.S. stores, premium positioning, ~$7 USD per cup, and no China operations today.', '["Market size and growth","Competition (Starbucks, Luckin, etc.)","Consumer insights","Entry mode (WFOE / JV / franchise)","City prioritization"]'::jsonb),
('pharma-ma', 'Pharma M&A decision', 'mergers_acquisitions', 'hard', 'Your client, a large pharmaceutical company, is considering acquiring an oncology-focused biotech for $5B. Evaluate whether the deal is worth doing.', 'The target has 3 pipeline drugs; 1 is in Phase III with expected launch in ~2 years. Current revenue is ~$200M (mostly licensing).', '["Strategic fit","Pipeline valuation","Deal valuation","Integration risk","Alternatives"]'::jsonb)
